use crate::block_cipher::BlockCipher;

use rand::rngs::OsRng;
use rand::RngCore;

pub trait StreamCipher {
    // Generates a random nonce and encrypt buf using the associated keystream.
    // Returns the nonce.
    fn encrypt_inplace(&self, buf: &mut [u8]) -> Box<[u8]>;
    fn decrypt_inplace(&self, nonce: &[u8], buf: &mut [u8]);

    fn encrypt(&self, pt: &[u8]) -> (Box<[u8]>, Box<[u8]>) {
        let mut result = Vec::from(pt);
        let nonce= self.encrypt_inplace(&mut result.as_mut_slice());
        return (nonce, result.into_boxed_slice());
    }
    fn decrypt(&self, nonce: &[u8], ct: &[u8]) -> Box<[u8]> {
        let mut result = Vec::from(ct);
        self.decrypt_inplace(nonce, &mut result.as_mut_slice());
        return result.into_boxed_slice();
    }
}

pub struct CounterMode {
    block_cipher: Box<dyn BlockCipher>,
}

impl CounterMode {
    pub fn new(block_cipher: Box<dyn BlockCipher>) -> CounterMode {
        let result = CounterMode { block_cipher };
        return result;
    }
}

impl StreamCipher for CounterMode {
    fn encrypt_inplace(&self, buf: &mut [u8]) -> Box<[u8]> {
        let mut nonce: [u8; 12] = [0; 12];
        OsRng.fill_bytes(&mut nonce);
        self.decrypt_inplace(&nonce, buf);
        return Box::new(nonce);
    }

    fn decrypt_inplace(&self, nonce: &[u8], buf: &mut [u8]) {
        if nonce.len() != 12 {
            panic!("nocne must be 12 bytes");
        }

        let needed_blocks = u32::try_from((buf.len() + 15) / 16).expect("msg too long");

        let mut pt: [u8; 16] = [0; 16];

        for i in 0..12 {
            pt[i] = nonce[i];
        }

        for block_idx in 0..needed_blocks {
            pt[12] = ((block_idx >> 24) & 0xFF) as u8;
            pt[13] = ((block_idx >> 16) & 0xFF) as u8;
            pt[14] = ((block_idx >> 8) & 0xFF) as u8;
            pt[15] = ((block_idx >> 0) & 0xFF) as u8;

            let ct = self.block_cipher.encrypt(pt);

            let start_idx = block_idx as usize * 16;

            for idx in start_idx..std::cmp::min(start_idx + 16, buf.len()) {
                buf[idx] ^= ct[idx - start_idx];
            }
        }
    }
}

--- iter 4 reasoning ---
Excellent recon. Now I fully understand the cipher.

**STACK:** Rust service over socat TCP:1337. Custom "ShuffledAes" block cipher used in CTR mode. We get a CTR encryption oracle for arbitrary plaintext, plus the encrypted flag.

**SURFACE:** 
- Encrypted flag (nonce + ct) printed at start
- CTR encryption oracle: send line → returns nonce + ct (keystream XOR pt)
- 21 round keys (random), NUMROUNDS=10

**BUG-HYP:** The "shuffled" AES has its operations reordered:
- AddRoundKey(k0)
- 10 rounds of just **SubBytes + AddRoundKey** (no diffusion!)
- 10 rounds of just **ShiftRows + MixColumns + AddRoundKey** (linear!)

**WHY:** The two halves don't interleave. The first 10 rounds operate **byte-independently** (SBOX is a per-byte permutation, XOR is per-byte). The last 10 rounds are entirely **linear** (ShiftRows, MixColumns, XOR are all GF(2)-linear/affine). So the whole cipher = (per-byte nonlinear function) followed by (affine linear function).

This means: `E(pt)[j] = sum_i M[j][i] * f_i(pt[i]) + c[j]` where each `f_i` is a byte→byte permutation and M is the linear layer over GF(2^8)... actually over GF(2) bits. We can recover the full cipher as a lookup-table structure via the CTR oracle, then decrypt the flag's keystream.

Let me think about the attack more concretely.

